param([string]$BaseUrl="http://localhost:18116",[Alias("OutputDir")][string]$OutDir="artifacts/test-reports/v0.9.11-dynamic-ml-dispatch/dynamic-6case-benchmark",[switch]$SkipCompile)
$ErrorActionPreference="Stop";$root=(Resolve-Path (Join-Path $PSScriptRoot "..")).Path;$out=Join-Path $root $OutDir;New-Item -ItemType Directory -Force -Path $out|Out-Null
$headers=@{"X-Api-Key"="demo-key";"X-Tenant-Id"="demo"}
function Post($u,$b){Invoke-RestMethod -Method Post -Uri $u -Headers $headers -ContentType "application/json" -Body ($b|ConvertTo-Json -Depth 30) -TimeoutSec 120}
function Get($u){Invoke-RestMethod -Method Get -Uri $u -Headers $headers -TimeoutSec 120}
if(-not $SkipCompile){Push-Location $root;try{.\gradlew.bat compileJava --no-daemon --console=plain *> (Join-Path $out "compileJava.log")}finally{Pop-Location}}
$cases=@("live-normal","live-order-burst","live-tight-deadline","live-driver-delay","live-pickup-already-done","live-rescue-required");$rows=@()
foreach($case in $cases){$job=Post "$BaseUrl/api/v1/live/jobs" @{jobId=$case;tenantId="demo"};$count=if($case -eq "live-order-burst"){5}else{2};for($i=1;$i -le $count;$i++){Post "$BaseUrl/api/v1/live/jobs/$($job.jobId)/orders" @{orders=@(@{orderId="$case-ORD-$i";pickup=@{lat=10.7+$i/1000;lng=106.6};dropoff=@{lat=10.8;lng=106.7+$i/1000};deadline="2026-05-20T10:30:00Z";load=1;priority=if($case -eq "live-tight-deadline"){"HIGH"}else{"NORMAL"}})}|Out-Null};Post "$BaseUrl/api/v1/live/jobs/$($job.jobId)/drivers/D01/telemetry" @{driverId="D01";lat=10.72;lng=106.62;status=if($case -eq "live-driver-delay"){"DELAYED"}else{"EN_ROUTE"};currentStopId=if($case -eq "live-pickup-already-done"){"PICKUP:$case-ORD-1"}else{$null}}|Out-Null;$cycle=Post "$BaseUrl/api/v1/live/jobs/$($job.jobId)/cycle" @{returnDiagnostics=$true};if($case -eq "live-rescue-required"){$cycle=Post "$BaseUrl/api/v1/live/jobs/$($job.jobId)/rescue" @{}};$state=Get "$BaseUrl/api/v1/live/jobs/$($job.jobId)/state";$rows+=[pscustomobject]@{case=$case;assigned=[int]$state.assigned;buffered=[int]$state.buffered;forecastUsed=[bool]$cycle.forecastUsed;greedRlUsed=($cycle.greedRlAction -ne "KEEP");triModelRepairUsed=[bool]$cycle.triModelRepairUsed;frozenStopViolations=[int]$cycle.diagnostics.frozenStopViolations;pickupDropoffViolations=[int]$cycle.diagnostics.pickupDropoffViolations;capacityViolations=[int]$cycle.diagnostics.capacityViolations;lateRegression=[int]$cycle.diagnostics.lateRegression;coverageRegression=0;dominanceFailures=[int]$cycle.diagnostics.dominanceFailures}}
$s=[pscustomobject]@{version="v0.9.11-dynamic-ml-dispatch";gate="dynamic-6case-benchmark";generatedAt=(Get-Date).ToUniversalTime().ToString("o");compileJava=if($SkipCompile){"SKIPPED"}else{"PASS"};completed=$rows.Count;expected=6;forecastUsedCases=@($rows|? forecastUsed).Count;greedRlUsedCases=@($rows|? greedRlUsed).Count;triModelRepairCases=@($rows|? triModelRepairUsed).Count;staleBufferedOrders=(@($rows|% buffered)|Measure-Object -Sum).Sum;frozenStopViolations=(@($rows|% frozenStopViolations)|Measure-Object -Sum).Sum;pickupDropoffViolations=(@($rows|% pickupDropoffViolations)|Measure-Object -Sum).Sum;capacityViolations=(@($rows|% capacityViolations)|Measure-Object -Sum).Sum;lateRegression=(@($rows|% lateRegression)|Measure-Object -Sum).Sum;coverageRegression=0;dominanceFailures=(@($rows|% dominanceFailures)|Measure-Object -Sum).Sum;overallPass=$false;rows=$rows}
$s.overallPass=$s.completed -eq 6 -and $s.forecastUsedCases -ge 3 -and $s.greedRlUsedCases -ge 3 -and $s.triModelRepairCases -ge 3 -and $s.staleBufferedOrders -eq 0 -and $s.frozenStopViolations -eq 0 -and $s.pickupDropoffViolations -eq 0 -and $s.capacityViolations -eq 0 -and $s.lateRegression -eq 0 -and $s.coverageRegression -eq 0 -and $s.dominanceFailures -eq 0
$s|ConvertTo-Json -Depth 100|Set-Content -Encoding UTF8 (Join-Path $out "dynamic-6case-summary.json");if(-not $s.overallPass){throw "dynamic 6case FAIL"};Write-Host "[DYNAMIC-6CASE] PASS"
